#!/usr/bin/env python3
from __future__ import annotations

import json
from pathlib import Path
from typing import Any, Dict, Optional

from controller import XiaodouyaController, load_selectors, validate_selectors_schema
from publish_xiaohongshu import (
    DEFAULT_EVIDENCE_ROOT,
    DEFAULT_SELECTORS_PATH,
    STEP_ORDER,
    run_workflow,
)

try:
    from mcp.server.fastmcp import FastMCP
except ImportError as exc:  # pragma: no cover
    raise SystemExit(f"Missing dependency: {exc}. Install with `pip install mcp`.")


mcp = FastMCP("xiaodouya-linux-win-control")


def _selectors_path(selectors_path: Optional[str]) -> Path:
    return Path(selectors_path) if selectors_path else DEFAULT_SELECTORS_PATH


def _evidence_root(evidence_dir: Optional[str]) -> Path:
    return Path(evidence_dir) if evidence_dir else DEFAULT_EVIDENCE_ROOT


def _status_from_jsonl(path: Path) -> Dict[str, Any]:
    if not path.exists():
        return {"ok": False, "error": f"jsonl report not found: {path}"}

    lines = path.read_text(encoding="utf-8").splitlines()
    if not lines:
        return {"ok": False, "error": "jsonl report is empty"}

    last = json.loads(lines[-1])
    return {
        "ok": True,
        "events": len(lines),
        "last_event": last,
        "prepublish_ready": bool(last.get("step") in {"screenshot_prepublish", "publish_click"} and last.get("ok")),
    }


def _controller_for_runtime(selectors_path: Optional[str], evidence_dir: Optional[str]) -> XiaodouyaController:
    return XiaodouyaController(
        selectors_path=_selectors_path(selectors_path),
        evidence_dir=_evidence_root(evidence_dir),
    )


@mcp.tool()
def xdy_run_workflow(
    content_file: str,
    mode: str = "prepublish",
    resume_from: Optional[str] = None,
    evidence_dir: Optional[str] = None,
    run_id: Optional[str] = None,
    selectors_path: Optional[str] = None,
) -> Dict[str, Any]:
    """Run full workflow: attach/start -> fill content -> prepublish/publish."""
    return run_workflow(
        content_file=content_file,
        mode=mode,
        resume_from=resume_from,
        evidence_dir=evidence_dir,
        run_id=run_id,
        selectors_path=selectors_path,
    )


@mcp.tool()
def xdy_step(
    step: str,
    action: str = "wait_for",
    text: str = "",
    selectors_path: Optional[str] = None,
    evidence_dir: Optional[str] = None,
) -> Dict[str, Any]:
    """Execute one step action: wait_for/click/type_text/screenshot/activate/attach_or_start."""
    controller = _controller_for_runtime(selectors_path, evidence_dir)

    if action == "attach_or_start":
        return controller.attach_or_start()
    if action == "activate":
        return controller.activate()
    if action == "wait_for":
        return controller.wait_for(step)
    if action == "click":
        return controller.click(step)
    if action == "type_text":
        return controller.type_text(step, text)
    if action == "screenshot":
        return controller.screenshot(step)


