@mcp.tool()
def xdy_resume(
    run_id: str,
    content_file: str,
    mode: str = "prepublish",
    resume_from: Optional[str] = None,
    evidence_dir: Optional[str] = None,
    selectors_path: Optional[str] = None,
) -> Dict[str, Any]:
    """Resume workflow from explicit step or auto-detected failed step from jsonl."""
    root = _evidence_root(evidence_dir)
    run_dir = root / run_id
    jsonl_path = run_dir / f"run_report_{run_id}.jsonl"

    start_step = resume_from
    if start_step is None and jsonl_path.exists():
        events = [json.loads(line) for line in jsonl_path.read_text(encoding="utf-8").splitlines() if line.strip()]
        failed = [e for e in events if not e.get("ok")]
        if failed:
            start_step = failed[-1]["step"]

    if start_step is None:
        start_step = STEP_ORDER[0]

    return run_workflow(
        content_file=content_file,
        mode=mode,
        resume_from=start_step,
        evidence_dir=str(root),
        run_id=run_id,
        selectors_path=selectors_path,
    )


@mcp.tool()
def xdy_get_status(run_id: str, evidence_dir: Optional[str] = None) -> Dict[str, Any]:
    """Get run status by reading run_report_<id>.jsonl/md."""
    root = _evidence_root(evidence_dir)
    run_dir = root / run_id
    jsonl_path = run_dir / f"run_report_{run_id}.jsonl"
    md_path = run_dir / f"run_report_{run_id}.md"

    status = _status_from_jsonl(jsonl_path)
    status.update(
        {
            "run_id": run_id,
            "report_jsonl": str(jsonl_path),
            "report_md": str(md_path),
            "report_md_exists": md_path.exists(),
        }
    )
    return status


@mcp.tool()
def xdy_list_selectors(selectors_path: Optional[str] = None) -> Dict[str, Any]:
    """List current selectors map."""
    path = _selectors_path(selectors_path)
    selectors = load_selectors(path)
    return {"ok": True, "selectors_path": str(path), "selectors": selectors}


@mcp.tool()
def xdy_validate_selectors(selectors_path: Optional[str] = None) -> Dict[str, Any]:
    """Validate selector schema and minimum strategy count."""
    path = _selectors_path(selectors_path)
    selectors = load_selectors(path)
    errors = validate_selectors_schema(selectors)
    return {
        "ok": len(errors) == 0,
        "selectors_path": str(path),
        "errors": errors,
    }


if __name__ == "__main__":
    mcp.run()

